const freeProviders = ['gmail.com','yahoo.com','yahoo.fr','hotmail.com','hotmail.fr','outlook.com','outlook.fr','live.com','live.fr','icloud.com','aol.com','gmx.com','protonmail.com','laposte.net','orange.fr','free.fr','wanadoo.fr'];

const body = $input.item.json.body || $input.item.json;
const name = (body.name || '').trim();
const email = (body.email || '').trim().toLowerCase();

let score = 0;
const reasons = [];

const domain = email.split('@')[1] || '';
if (domain && !freeProviders.includes(domain)) {
  score += 2;
  reasons.push('Domaine email professionnel');
}

if (name.split(/\s+/).filter(Boolean).length >= 2) {
  score += 1;
  reasons.push('Nom complet renseigné');
}

const tier = score >= 2 ? 'prioritaire' : 'standard';

return {
  json: {
    name,
    email,
    domain,
    score,
    tier,
    reasons,
    source: body.source || null,
    submittedAt: body.submittedAt || new Date().toISOString(),
    scoredAt: new Date().toISOString()
  }
};
